def solution():
    # Define the birth year of Jane
    birth_year = 1957

    # Calculate full retirement age based on the given logic
    if birth_year < 1943:
        raise ValueError("This function is applicable only for birth years 1943 and later.")

    # Check various conditions for full retirement age
    if birth_year >= 1960:
        fra = 67
    elif birth_year < 1955:
        fra = 66
    else:
        # Incremental increase in retirement age from 1955 to 1959
        fra = 66 + (birth_year - 1954) * 2 // 12

    # Return the full retirement age rounded to nearest integer
    return round(fra)

# Print the solution
print(solution())
